import jsonimport socketimport sysimport osfrom Searcher import screamimport timefrom tqdm import tqdmif len(sys.argv) > 1:    target_dir = sys.argv[1]    os.chdir(target_dir)    print(f"Файлы сохранятся в {target_dir}")HOST = socket.gethostbyname(socket.gethostname())PORT = 8080devices = []server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)server.setblocking(False)server.bind((HOST, PORT))server.listen()while True:    try:        conn, adr = server.accept()        print("Connected by", adr)        conn.setblocking(True)        break    except BlockingIOError:        scream()        time.sleep(2)def recvall(conn, length):    data = bytearray()    while len(data) < length:        packet = conn.recv(length - len(data))        if not packet:            return None        data.extend(packet)    return bytes(data)def recv_message(conn, l = 4):    raw_msglen = recvall(conn, l)    if not raw_msglen:        return None    msglen = int.from_bytes(raw_msglen, byteorder='big')    return recvall(conn, msglen)received_data = json.loads(recv_message(conn).decode('utf-8'))received_bytes = 0chunk_size = 8192file_size = received_data['size']file_name = received_data['name']with open(file_name, 'wb') as f:    with tqdm(total=file_size, unit='B', unit_scale=True, desc=f"Прием {file_name}") as progress:        while received_bytes < file_size:            remaining = file_size - received_bytes            to_read = min(remaining, chunk_size)            chunk = conn.recv(to_read)            if not chunk:                print("Connection closed")                break            f.write(chunk)            received_bytes += len(chunk)            progress.update(len(chunk))print("\nФайл успешно сохранен!")# print(data)